var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"후아, 죽다 살아나니까 이 더러운 길바닥이 레드 카펫으로 보이네.","JPN":"はあ、死にかけた後だからか、この汚い道がレッドカーペットに見えるな。","ENG":"Phew, it feels like I'm walking on a red carpet even on this nasty road now that I've made it out alive.","TWN":"呼！真是九死一生，連這骯髒的路面看起來都像紅地毯呢！"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"누가 아니래. 우리 이 정도면 베테랑 용병 아냐?","JPN":"だな。俺らももはやベテラン傭兵じゃないか？","ENG":"Tell me about it. If this doesn't make us veteran mercenaries, I don't know what will.","TWN":"就是說，我們這種程度根本就是老鳥傭兵吧？"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"업무 종료. 약속했던 대금 지불을 요구합니다, 휴먼.","JPN":"業務終了。約束した代金の支払いを要求します、ヒューマン。","ENG":"The job is done. I request payment as promised, human.","TWN":"業務完成。請支付約定的款項，人類。"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"수고했다. 돈이라면 여기 봉투 안에 있어.","JPN":"ご苦労様。金ならこの封筒の中だ。","ENG":"Good job. The money's in this envelope.","TWN":"辛苦了，錢就在這個信封袋裡。"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L9_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"하지만 주기 전에 한 가지 묻고 싶군. 괜찮겠나.","JPN":"しかし、渡す前に一つ聞きたい。いいか？","ENG":"But before I pay you, I'd like to ask just one question. Is that all right?","TWN":"但在你拿走前，我想問你一個問題，可以嗎？"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"제가 대답해 드릴 수 있는 질문이라면.","JPN":"答えられる質問であれば。","ENG":"Certainly. Assuming it is a question that I can answer.","TWN":"我回答得出來的話。"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"너는……. 카운터인가?","JPN":"あんたは……カウンターか？","ENG":"Are you… a Counter?","TWN":"你是……制裁者嗎？"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"그 질문에 함축적인 의미가 있다는 전제로 대답드리겠습니다.","JPN":"その質問には隠された意図があることを前提にお答えします。","ENG":"I can sense your \\"one\\" question actually involves many. But my answer is simple.","TWN":"我會在這個問題別有用意的前提下回答你。"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"저는 기계입니다. 이상입니다.","JPN":"私は機械です。以上です。","ENG":"I am a machine. That is all.","TWN":"我是機器，以上。"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"안드로이드라면 그라운드 원에서 본 적 있어.","JPN":"アンドロイドならグラウンド・ワンで見たことがある。","ENG":"Well, I've seen androids in Ground One before.","TWN":"人形機器人的話，我在G1有看過。"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"하지만 그 중에서도 트럭을 집어던지는 기종이 있다는 얘기는 못 들었다.","JPN":"しかし、その中にトラックを投げつける機種があるなんて話は聞いていない。","ENG":"But none of them could throw a truck, to my knowledge.","TWN":"但我沒聽說過當中有會扔卡車的機種。"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"물론입니다. 아무리 설명해도 휴먼들은 카운터라고 이해하더군요.","JPN":"もちろんです。いくら説明してもヒューマンたちはカウンターだと理解してしまいます。","ENG":"Of course. No matter how much I explain, humans simply believe that I'm a Counter.","TWN":"當然。因為無論怎麼解釋，人類都只會理解爲制裁者。"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"……최근 만난 한 명을 제외하면 말입니다.","JPN":"……最近会った一人を除けば、ですが。","ENG":"…Except one person I recently met.","TWN":"……除了我最近認識的那個人。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"몇 차례 시도 후, 의문을 표한 휴먼들을 설득하려는 시도는 포기했습니다.","JPN":"何度か試みた結果、疑問を示したヒューマンたちを説得するのは諦めました。","ENG":"After several attempts, I've given up on trying to convince humans otherwise.","TWN":"幾次嘗試後，我已經放棄試圖說服表示疑問的人類。"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"설득해도 저에게 리턴은 없으니까요. 결국 눈으로 확인하지 않으면 못 믿더군요.","JPN":"説得しても私が得することはありません。結局、自身の目で確認できなければ信じてくれないのです。","ENG":"I have nothing to gain from it, after all. Humans never seem to believe anything they don't witness with their own eyes.","TWN":"因為根本就是對牛彈琴，若非親眼確認，人類是不會相信的。"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"신기하지 않습니까. 혁신적인 구조의 기계보다 카운터라고 받아들이는 경향이.","JPN":"不思議だと思いませんか？　革新的な構造の機械よりも、カウンターだと受け止めてしまう傾向があるのです。","ENG":"Is it not fascinating? They're more willing to accept that I'm a Counter than an innovative, intricate machine.","TWN":"不覺得很神奇嗎。人類情願接受制裁者的這個說法，也不願相信有著革新架構的機器。"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}}]`);export{e as default};